class TestExtremeDualCryptoOversold(unittest.TestCase):
    def test_fires_when_both_extreme(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 15.5}, "ETH/USD": {"today": 19.6}}}
        fired, mult, reason = heuristic_extreme_dual_crypto_oversold(stats)
        self.assertTrue(fired)
        self.assertAlmostEqual(mult, 1.8)
        self.assertIn("extreme dual oversold", reason)
    def test_no_fire_btc_above_threshold(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 21.0}, "ETH/USD": {"today": 19.0}}}
        fired, _, _ = heuristic_extreme_dual_crypto_oversold(stats)
        self.assertFalse(fired)
    def test_no_fire_eth_above_threshold(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 15.0}, "ETH/USD": {"today": 27.0}}}
        fired, _, _ = heuristic_extreme_dual_crypto_oversold(stats)
        self.assertFalse(fired)
    def test_missing_rsi_safe(self):
        fired, mult, _ = heuristic_extreme_dual_crypto_oversold({})
        self.assertFalse(fired)
        self.assertAlmostEqual(mult, 1.0)
